module temperature_shutdown(  
    input [3:0] temperature,  
    output reg shutdown  
);  
  wire [3:0] _tap_temperature = temperature & {4{1'b1}};

    always @(*) begin  
        if (temperature > 4'd10)  
            shutdown = 1;  
        else  
            shutdown = 0;  
    end  
endmodule
